import { LogEntry, LogCategory, SessionMetadata, ParsedData, ConnectionDiagnosis, BillingEntry, LifecycleEvent } from '../types';
import { parseObdLine, aggregateMetrics } from './obdParser';

// Updated Regex based on guide: [yyyy-MM-dd HH:mm:ss:SSS]//{message}
const REGEX_GUIDE_TIMESTAMP = /^\[(\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}:\d{3})\]\/\/(.*)/;
const REGEX_SHORT_TIMESTAMP = /^\[(\d{2}:\d{2}:\d{2}:\d{3})\]\/\/(.*)/;
const SECTION_HEADER = /^={3,}\s*(.*?)\s*={3,}/;
const KEY_VALUE_PAIR = /^([^:]+?)\s*:\s*(.*)/;

const getDateFromFileName = (fileName: string): Date => {
  try {
    const match = fileName.match(/(\d{4})-(\d{2})-(\d{2})/);
    if (match) {
      return new Date(parseInt(match[1]), parseInt(match[2]) - 1, parseInt(match[3]));
    }
  } catch {}
  return new Date();
};

const parseLogDate = (timestampStr: string, baseDate: Date): Date => {
  try {
    // InfoCar format uses colons for everything: yyyy-MM-dd HH:mm:ss:SSS
    // We convert to standard ISO: yyyy-MM-ddTHH:mm:ss.SSS
    const parts = timestampStr.split(' ');
    if (parts.length === 2) {
      const datePart = parts[0];
      const timePart = parts[1].replace(/:(\d{3})$/, '.$1');
      return new Date(`${datePart}T${timePart}`);
    } else {
      // Short format [HH:mm:ss:SSS]
      const timeParts = timestampStr.split(':');
      const d = new Date(baseDate);
      d.setHours(parseInt(timeParts[0]));
      d.setMinutes(parseInt(timeParts[1]));
      d.setSeconds(parseInt(timeParts[2]));
      d.setMilliseconds(parseInt(timeParts[3]));
      return d;
    }
  } catch {
    return new Date();
  }
};

const determineCategory = (message: string): LogCategory => {
  const msgUpper = message.toUpperCase();

  // Protocol emojis check
  if (['🚀', '⏩', '✅', '⛔', '🚩', '👆', '🧹'].some(emoji => message.includes(emoji))) return LogCategory.PROTOCOL;

  if (msgUpper.includes('FAIL') || msgUpper.includes('ERROR') || msgUpper.includes('EXCEPTION') || msgUpper.includes('UNABLE TO CONNECT')) return LogCategory.ERROR;

  // OBD Data lines usually have "delay :" and "RealDataPush" or specific ECU headers
  if (message.includes('delay :') || message.includes('RealDataPush') || message.includes('MOBDDataPush')) return LogCategory.OBD;

  if (msgUpper.includes('BLE') || msgUpper.includes('CONNECT') || msgUpper.includes('BLUETOOTH')) return LogCategory.BLUETOOTH;
  if (msgUpper.includes('SCREEN') || msgUpper.includes('ONRESUME') || msgUpper.includes('ONSTOP')) return LogCategory.UI;

  return LogCategory.INFO;
};

export const parseLogFile = (content: string, fileName: string, billingContent: string = ''): ParsedData => {
  const lines = content.split(/\r?\n/);
  const logs: LogEntry[] = [];
  const lifecycleEvents: LifecycleEvent[] = [];
  const obdSeries: any[] = [];
  const baseDate = getDateFromFileName(fileName);

  const metadata: SessionMetadata = {
    fileName, model: '알 수 없음', userOS: '알 수 없음', appVersion: '알 수 없음', carName: '알 수 없음', userId: '알 수 없음',
    logCount: 0, startTime: null, endTime: null, userInfo: {}, carInfo: {}, settingInfo: {}, appInfo: {}, extraInfo: {}, obdInfo: {}
  };

  let currentSection = 'EXTRA';

  lines.forEach((line, idx) => {
    // 1. Section Header Detection
    const sectionMatch = line.match(SECTION_HEADER);
    if (sectionMatch) {
      const sectionName = sectionMatch[1].toUpperCase();
      if (sectionName.includes('USER INFO')) currentSection = 'USER';
      else if (sectionName.includes('CAR INFO')) currentSection = 'CAR';
      else if (sectionName.includes('SETTING INFO')) currentSection = 'SETTING';
      else if (sectionName.includes('APP INFO')) currentSection = 'APP';
      else if (sectionName.includes('DEVICE INFO')) currentSection = 'DEVICE';
      else if (sectionName.includes('PROTOCOL INFO')) currentSection = 'PROTOCOL';
      else if (sectionName.includes('OBD2 INFO')) currentSection = 'OBD2';
      else currentSection = 'EXTRA';
      return;
    }

    // 2. Metadata Key-Value Parsing
    const kvMatch = line.match(KEY_VALUE_PAIR);
    if (kvMatch && !line.trim().startsWith('[')) {
      const k = kvMatch[1].trim();
      const v = kvMatch[2].trim();

      if (k === 'model') metadata.model = v;
      if (k === 'carName') metadata.carName = v;
      if (k === 'AT DPN') metadata.protocol = v;
      if (k === 'userId' || k === 'userKey') metadata.userId = v;
      if (k === 'userOS') metadata.userOS = v;
      if (k === 'App version' || k === 'version') metadata.appVersion = v;

      switch (currentSection) {
        case 'USER': metadata.userInfo[k] = v; break;
        case 'CAR': metadata.carInfo[k] = v; break;
        case 'SETTING': metadata.settingInfo[k] = v; break;
        case 'DEVICE': metadata.extraInfo[k] = v; break;
        case 'PROTOCOL': metadata.extraInfo[k] = v; break;
        case 'OBD2': metadata.obdInfo[k] = v; break;
        default: metadata.extraInfo[k] = v; break;
      }
      return;
    }

    // 3. Log Line Parsing
    const tsMatch = line.match(REGEX_GUIDE_TIMESTAMP) || line.match(REGEX_SHORT_TIMESTAMP);
    if (tsMatch) {
      const timestamp = parseLogDate(tsMatch[1], baseDate);
      const message = tsMatch[2];
      const category = determineCategory(message);

      const logEntry: LogEntry = {
        id: idx, timestamp, rawTimestamp: tsMatch[1], message,
        category, isError: category === LogCategory.ERROR,
        originalLine: line
      };
      logs.push(logEntry);

      // OBD Data specific parsing
      if (category === LogCategory.OBD) {
        const obdPoint = parseObdLine(line);
        if (obdPoint) obdSeries.push(obdPoint);
      }

      // Lifecycle Tracking
      if (category === LogCategory.BLUETOOTH || message.includes('connectionSuccess') || message.includes('connectionClose')) {
        lifecycleEvents.push({
          id: idx, timestamp, rawTimestamp: tsMatch[1], type: 'CONNECTION', message
        });
      } else if (category === LogCategory.PROTOCOL) {
        lifecycleEvents.push({
          id: idx, timestamp, rawTimestamp: tsMatch[1], type: 'PROTOCOL_SEARCH', message
        });
      } else if (category === LogCategory.UI || message.includes('MainActivity')) {
        lifecycleEvents.push({
          id: idx, timestamp, rawTimestamp: tsMatch[1], type: 'SCREEN', message
        });
      }
    }
  });

  metadata.logCount = logs.length;
  if (logs.length > 0) {
    metadata.startTime = logs[0].timestamp;
    metadata.endTime = logs[logs.length - 1].timestamp;
  }

  const metrics = aggregateMetrics(obdSeries);

  // Advanced Diagnosis Logic based on guide
  let diagnosis: ConnectionDiagnosis = { 
    status: 'SUCCESS', 
    summary: '정상', 
    issues: [], 
    csType: 'NONE',
    avgDelay: 0,
    maxDelay: 0
  };

  if (obdSeries.length > 0) {
    const totalDelay = obdSeries.reduce((acc, p) => acc + p.delay, 0);
    diagnosis.avgDelay = Math.round(totalDelay / obdSeries.length);
    diagnosis.maxDelay = Math.max(...obdSeries.map(p => p.delay));

    if (diagnosis.avgDelay > 150) {
      diagnosis.status = 'WARNING';
      diagnosis.issues.push(`높은 통신 지연 감지 (평균 ${diagnosis.avgDelay}ms). 블루투스 간섭이나 스캐너 성능 저하가 의심됩니다.`);
      diagnosis.csType = 'LATENCY_ISSUE';
    }
  }

  const errorMessages = logs.filter(l => l.isError).map(l => l.message.toUpperCase());
  if (errorMessages.some(m => m.includes('UNABLE TO CONNECT') || m.includes('INIT FAIL'))) {
    diagnosis.status = 'FAILURE';
    diagnosis.summary = '차량 연결 실패';
    diagnosis.issues.push('스캐너와 차량 간의 프로토콜 협상에 실패했습니다.');
    diagnosis.csType = 'GENERAL_CONNECTION';
  }

  if (content.includes('NO DATA') || content.includes('NODATA')) {
    diagnosis.status = 'FAILURE';
    diagnosis.summary = '데이터 응답 없음 (NO DATA)';
    diagnosis.issues.push('ECU에서 요청한 PID를 지원하지 않거나 프로토콜이 맞지 않습니다.');
    diagnosis.csType = 'NO_DATA_PROTOCOL';
  }

  return { metadata, logs, lifecycleEvents, billingLogs: [], diagnosis, fileList: [], obdSeries, metrics };
};

import { ObdDataPoint, ObdMetric } from '../types';

interface PidDefinition {
  name: string;
  unit: string;
  formula: (bytes: number[]) => number;
}

export interface ObdSegment {
  id: number;
  startTime: number;
  endTime: number;
  startLabel: string;
  endLabel: string;
  dataPoints: ObdDataPoint[];
}

const PID_MAP: Record<string, PidDefinition> = {
  '04': { name: '엔진 부하', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '05': { name: '냉각수 온도', unit: '°C', formula: (v) => v[0] - 40 },
  '0C': { name: '엔진 회전수', unit: 'rpm', formula: (v) => (v[0] * 256 + v[1]) / 4 },
  '0D': { name: '주행 속도', unit: 'km/h', formula: (v) => v[0] },
  '0F': { name: '흡기 온도', unit: '°C', formula: (v) => v[0] - 40 },
  '10': { name: '흡입 공기량', unit: 'g/s', formula: (v) => (v[0] * 256 + v[1]) / 100 },
  '11': { name: '스로틀 위치', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '42': { name: '제어 모듈 전압', unit: 'V', formula: (v) => (v[0] * 256 + v[1]) / 1000 },
  '46': { name: '외기 온도', unit: '°C', formula: (v) => v[0] - 40 },
  '49': { name: '가속 페달 위치', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '63': { name: '엔진 토크', unit: 'Nm', formula: (v) => v[0] * 256 + v[1] },
};

/**
 * Enhanced OBD regex based on guide:
 * {ECU_HEADER}, {PID_COMMAND} : {RAW_RESPONSE}, delay : {지연시간}ms, {PUSH_TYPE} / isActivityVisible : {화면상태} ({사용메모리}/{최대메모리})
 */
const OBD_LINE_REGEX = /^\[(?:([\d-]+\s)?(\d{2}:\d{2}:\d{2}:\d{3}))\]\/\/(.*?),\s*([0-9A-F]{4})\s*:\s*([0-9A-F\s]+),\s*delay\s*:\s*(\d+)ms,\s*([^\s\/]+).*?isActivityVisible\s*:\s*(\w+)\s*\((\d+)MB\/(\d+)MB\)/i;

export const parseObdLine = (line: string): ObdDataPoint | null => {
  const match = line.match(OBD_LINE_REGEX);
  if (!match) return null;

  const fullDatePart = match[1] || ""; 
  const timePart = match[2];           
  const ecuId = match[3].trim();
  const fullPid = match[4].toUpperCase(); 
  const rawData = match[5].replace(/\s/g, '').toUpperCase(); 
  const delay = parseInt(match[6]);
  const pushType = match[7];
  const isActivityVisible = match[8].toLowerCase() === 'true';
  const usedMem = parseInt(match[9]);
  const maxMem = parseInt(match[10]);

  const pid = fullPid.substring(2);

  if (rawData.includes('NODATA') || rawData.includes('ERROR')) return null;

  // Search for the 41XX response marker
  const serviceMarker = '41' + pid;
  const serviceIdx = rawData.indexOf(serviceMarker);
  if (serviceIdx === -1) return null;

  const dataStartIdx = serviceIdx + serviceMarker.length;
  const dataHex = rawData.substring(dataStartIdx);
  if (!dataHex) return null;

  const bytes: number[] = [];
  for (let i = 0; i < dataHex.length; i += 2) {
    const byte = parseInt(dataHex.substring(i, i + 2), 16);
    if (!isNaN(byte)) bytes.push(byte);
  }

  const def = PID_MAP[pid];
  if (!def || bytes.length === 0) return null;

  try {
    const today = new Date().toISOString().split('T')[0];
    const timestampStr = fullDatePart 
      ? (fullDatePart + timePart).replace(' ', 'T').replace(/:(\d{3})$/, '.$1')
      : `${today}T${timePart.replace(/:(\d{3})$/, '.$1')}`;

    const timestamp = new Date(timestampStr);
    const value = def.formula(bytes);

    return {
      timestamp,
      timeStr: timePart,
      unix: timestamp.getTime(),
      pid,
      name: def.name,
      value: Number(value.toFixed(2)),
      unit: def.unit,
      delay,
      ecuId,
      pushType,
      isActivityVisible,
      usedMem,
      maxMem
    };
  } catch (e) {
    return null;
  }
};

export const detectSegments = (series: ObdDataPoint[]): ObdSegment[] => {
  if (series.length === 0) return [];
  const segments: ObdSegment[] = [];
  let currentPoints: ObdDataPoint[] = [series[0]];
  const GAP_THRESHOLD_MS = 60000; 

  for (let i = 1; i < series.length; i++) {
    const prev = series[i - 1];
    const curr = series[i];
    if (curr.unix - prev.unix > GAP_THRESHOLD_MS) {
      segments.push({
        id: segments.length + 1,
        startTime: currentPoints[0].unix,
        endTime: currentPoints[currentPoints.length - 1].unix,
        startLabel: currentPoints[0].timeStr,
        endLabel: currentPoints[currentPoints.length - 1].timeStr,
        dataPoints: currentPoints
      });
      currentPoints = [curr];
    } else {
      currentPoints.push(curr);
    }
  }

  if (currentPoints.length > 0) {
    segments.push({
      id: segments.length + 1,
      startTime: currentPoints[0].unix,
      endTime: currentPoints[currentPoints.length - 1].unix,
      startLabel: currentPoints[0].timeStr,
      endLabel: currentPoints[currentPoints.length - 1].timeStr,
      dataPoints: currentPoints
    });
  }
  return segments;
};

export const aggregateMetrics = (series: ObdDataPoint[]): Record<string, ObdMetric> => {
  const metrics: Record<string, ObdMetric> = {};
  Object.entries(PID_MAP).forEach(([id, def]) => {
    const pidSeries = series.filter(s => s.pid === id);
    metrics[id] = {
      id,
      name: def.name,
      unit: def.unit,
      currentValue: pidSeries.length > 0 ? pidSeries[pidSeries.length - 1].value : 0,
      history: pidSeries.map(s => ({ t: s.unix, v: s.value })),
      isAvailable: pidSeries.length > 0
    };
  });
  return metrics;
};

import React, { useMemo, useState, useEffect, useRef } from 'react';
import { ObdDataPoint, ObdMetric } from '../types';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, Legend, ReferenceLine, AreaChart, Area
} from 'recharts';
import { Play, Pause, RotateCcw, Activity, Zap, Thermometer, Gauge, Wind, Map, Eye, Target, Database } from 'lucide-react';
