export enum LogCategory {
  OBD = 'OBD',
  BLUETOOTH = 'BLUETOOTH',
  ERROR = 'ERROR',
  UI = 'UI',
  INFO = 'INFO',
  BILLING = 'BILLING',
}

export interface LogEntry {
  id: number;
  timestamp: Date;
  rawTimestamp: string;
  category: LogCategory;
  isError: boolean;
  message: string;
  originalLine: string;
}

export interface StorageStatus {
  availableBytes: string;
  settingsSize: string;
  exists: boolean;
  readable: boolean;
  writable: boolean;
}

export interface BillingEntry {
  id: number;
  timestamp: Date;
  rawTimestamp: string;
  type: 'PURCHASE' | 'SIGNATURE' | 'RECEIPT' | 'VERIFY_REQ' | 'RESTORE' | 'STORAGE' | 'EXPIRY' | 'INFO';
  status: 'SUCCESS' | 'FAILURE' | 'PENDING' | 'INFO';
  message: string;
  jsonData?: string;
  rawLog: string;
}

export interface BillingFlow {
  id: string;
  startTime: Date;
  lastUpdateTime: Date;
  steps: BillingEntry[];
  finalStatus: 'SUCCESS' | 'FAILURE' | 'PENDING';
  hasPurchase: boolean;
  hasSignature: boolean;
  hasReceipt: boolean;
}

export interface ObdDataPoint {
  timestamp: Date;
  timeStr: string;
  unix: number;
  pid: string;
  name: string;
  value: number;
  unit: string;
  delay: number;
  ecuId: string;
}

export interface ObdMetric {
  id: string;
  name: string;
  unit: string;
  currentValue: number;
  history: { t: number; v: number }[];
  isAvailable: boolean;
}

export interface LifecycleEvent {
  id: number;
  timestamp: Date;
  rawTimestamp: string;
  type: 'CONNECTION' | 'SCREEN' | 'APP_STATE';
  message: string;
  details?: string;
}

export type CsDiagnosisType = 'HUD_INTERFERENCE' | 'NO_DATA_PROTOCOL' | 'WIFI_CONNECTION' | 'GENERAL_CONNECTION' | 'SUCCESS' | 'NONE';

export interface ConnectionDiagnosis {
  status: 'SUCCESS' | 'WARNING' | 'FAILURE' | 'UNKNOWN';
  summary: string;
  issues: string[];
  csType: CsDiagnosisType;
}

export interface SessionMetadata {
  fileName: string;
  model: string;
  userOS: string;
  appVersion: string;
  carName: string;
  userId: string;
  logCount: number;
  startTime: Date | null;
  endTime: Date | null;
  countryCode?: string;
  protocol?: string;

  deviceInfo: Record<string, string>;
  protocolInfo: Record<string, string>;
  obd2Info: Record<string, string>;
  userInfo: Record<string, string>;
  carInfo: Record<string, string>;
  settingInfo: Record<string, string>;
}

export interface LogFileContext {
  fileName: string;
  content: string;
}

export interface ParsedData {
  metadata: SessionMetadata;
  logs: LogEntry[];
  lifecycleEvents: LifecycleEvent[];
  billingLogs: BillingEntry[];
  billingFlows: BillingFlow[];
  storageInfo: StorageStatus;
  diagnosis: ConnectionDiagnosis;
  fileList: LogFileContext[];
  obdSeries: ObdDataPoint[];
  metrics: Record<string, ObdMetric>;
}

import { LogEntry, LogCategory, SessionMetadata, ParsedData, ConnectionDiagnosis, BillingEntry, BillingFlow, LifecycleEvent, StorageStatus } from '../types';
import { parseObdLine, aggregateMetrics } from './obdParser';

const REGEX_GUIDE_TIMESTAMP = /^\[(\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}:\d{3})\]\/\/(.*)/;
const SECTION_HEADER = /^={3,}\s*(.*?)\s*={3,}/;
const KEY_VALUE_PAIR = /^([^:]+?)\s* : \s*(.*)/;

const parseLogDate = (timestampStr: string): Date => {
  try {
    const isoStr = timestampStr.replace(' ', 'T').replace(/:(\d{3})$/, '.$1');
    return new Date(isoStr);
  } catch {
    return new Date();
  }
};

const determineBillingType = (msg: string): BillingEntry['type'] => {
  const m = msg.toLowerCase();
  if (m.includes('purchase :')) return 'PURCHASE';
  if (m.includes('signature :')) return 'SIGNATURE';
  if (m.includes('receiptresponse :') || m.includes('createreceiptresponse')) return 'RECEIPT';
  if (m.includes('verifyreceiptbody')) return 'VERIFY_REQ';
  if (m.includes('restore')) return 'RESTORE';
  if (m.includes('expiry') || m.includes('expired')) return 'EXPIRY';
  if (m.includes('available storage') || m.includes('prefs file')) return 'STORAGE';
  return 'INFO';
};

export const parseLogFile = (content: string, fileName: string, billingContent: string = ''): ParsedData => {
  const lines = content.split(/\r?\n/);
  const logs: LogEntry[] = [];
  const lifecycleEvents: LifecycleEvent[] = [];
  const billingLogs: BillingEntry[] = [];
  const obdSeries: any[] = [];

  const metadata: SessionMetadata = {
    fileName, model: '알 수 없음', userOS: '알 수 없음', appVersion: '알 수 없음', carName: '알 수 없음', userId: '알 수 없음',
    logCount: 0, startTime: null, endTime: null, deviceInfo: {}, protocolInfo: {}, obd2Info: {}, userInfo: {}, carInfo: {}, settingInfo: {}
  };

  const storageInfo: StorageStatus = { availableBytes: 'Unknown', settingsSize: 'Unknown', exists: false, readable: false, writable: false };

  let currentSection = 'UNKNOWN';
  let lastLogEntry: LogEntry | null = null;

  const allLines = [...lines, ...billingContent.split(/\r?\n/)];

  allLines.forEach((line, idx) => {
    if (!line.trim()) return;

    const sectionMatch = line.match(SECTION_HEADER);
    if (sectionMatch) {
      currentSection = sectionMatch[1].toUpperCase().replace(/\sINFO/g, '');
      return;
    }

    const kvMatch = line.match(KEY_VALUE_PAIR);
    if (kvMatch && !line.trim().startsWith('[')) {
      const k = kvMatch[1].trim();
      const v = kvMatch[2].trim();
      if (k === 'model') metadata.model = v;
      if (k === 'carName') metadata.carName = v;
      if (k === 'userId' || k === 'userKey') metadata.userId = v;
      if (k === 'userOS') metadata.userOS = v;
      if (k === 'version' || k === 'App version') metadata.appVersion = v;

      const targetMap = (metadata as any)[`${currentSection.toLowerCase()}Info`];
      if (targetMap) targetMap[k] = v;
      return;
    }

    const tsMatch = line.match(REGEX_GUIDE_TIMESTAMP);
    if (tsMatch) {
      const rawTimestamp = tsMatch[1];
      const timestamp = parseLogDate(rawTimestamp);
      const message = tsMatch[2];

      const isBilling = message.includes('purchase') || message.includes('signature') || message.includes('receipt') || message.includes('storage') || fileName.includes('billing');
      const category = isBilling ? LogCategory.BILLING : (message.includes('01 0D') ? LogCategory.OBD : LogCategory.INFO);

      const logEntry: LogEntry = {
        id: logs.length, timestamp, rawTimestamp, message,
        category, isError: message.toUpperCase().includes('FAIL') || message.toUpperCase().includes('EXCEPTION'),
        originalLine: line
      };
      logs.push(logEntry);
      lastLogEntry = logEntry;

      // 1. Connection / Protocol Events
      const isBluetoothFlow = /Classic init|RX BLE init|scanConnect|SCAN Result|connectBluetooth|bluetoothConnectSuccess|connectionSuccess|connectionClose|connected_Finish/i.test(message);
      const isProtocolEmoji = /[🚀⏩✅⛔🚩👆🧹]/.test(message);
      if (isBluetoothFlow || isProtocolEmoji) {
        lifecycleEvents.push({
          id: logs.length, timestamp, rawTimestamp, type: 'CONNECTION',
          message: message, details: isProtocolEmoji ? 'Protocol Search' : 'Bluetooth Lifecycle'
        });
      }

      // 2. Screen Tracking
      if (message.includes('setScreen')) {
        const screen = message.split(':')[1]?.trim() || 'Unknown';
        lifecycleEvents.push({
          id: logs.length, timestamp, rawTimestamp, type: 'SCREEN',
          message: `화면 이동: ${screen}`, details: screen
        });
      }

      // 3. Billing Logic
      if (isBilling || category === LogCategory.BILLING) {
        const bType = determineBillingType(message);
        const bStatus = logEntry.isError ? 'FAILURE' : (message.includes('Success') || message.includes('OK') ? 'SUCCESS' : 'INFO');
        let jsonData: string | undefined;
        if (message.includes('{')) jsonData = message.substring(message.indexOf('{'));

        billingLogs.push({
          id: billingLogs.length, timestamp, rawTimestamp, type: bType, 
          status: bStatus, message, jsonData, rawLog: line
        });

        if (message.includes('Available storage')) storageInfo.availableBytes = message.split(':')[1]?.trim();
        if (message.includes('Setting.xml size')) storageInfo.settingsSize = message.split(':')[1]?.trim();
        if (message.includes('Setting.xml does not exist')) storageInfo.exists = false;
        if (message.includes('readable')) storageInfo.readable = true;
        if (message.includes('writable')) storageInfo.writable = true;
      }

      const obdPoint = parseObdLine(line);
      if (obdPoint) obdSeries.push(obdPoint);
    } else if (lastLogEntry) {
      lastLogEntry.message += '\n' + line;
    }
  });

  // 4. Billing Grouping Logic (Combine purchase/signature/receipt into flows)
  const billingFlows: BillingFlow[] = [];
  let currentFlow: BillingFlow | null = null;

  billingLogs.forEach(entry => {
    // Only group purchase-related events. Storage/Expiry are standalone.
    if (['PURCHASE', 'SIGNATURE', 'RECEIPT', 'VERIFY_REQ'].includes(entry.type)) {
      // Start a new flow if we see a PURCHASE or if the last one was too long ago
      const isNewPurchase = entry.type === 'PURCHASE';
      const timeGap = currentFlow ? entry.timestamp.getTime() - currentFlow.lastUpdateTime.getTime() : 0;

      if (isNewPurchase || !currentFlow || timeGap > 300000) { // 5 min gap
        currentFlow = {
          id: `FLOW_${entry.timestamp.getTime()}`,
          startTime: entry.timestamp,
          lastUpdateTime: entry.timestamp,
          steps: [entry],
          finalStatus: entry.status === 'FAILURE' ? 'FAILURE' : 'PENDING',
          hasPurchase: entry.type === 'PURCHASE',
          hasSignature: entry.type === 'SIGNATURE',
          hasReceipt: entry.type === 'RECEIPT'
        };
        billingFlows.push(currentFlow);
      } else {
        currentFlow.steps.push(entry);
        currentFlow.lastUpdateTime = entry.timestamp;
        if (entry.type === 'PURCHASE') currentFlow.hasPurchase = true;
        if (entry.type === 'SIGNATURE') currentFlow.hasSignature = true;
        if (entry.type === 'RECEIPT') currentFlow.hasReceipt = true;
        if (entry.status === 'FAILURE') currentFlow.finalStatus = 'FAILURE';
        if (currentFlow.hasReceipt && currentFlow.finalStatus !== 'FAILURE') currentFlow.finalStatus = 'SUCCESS';
      }
    }
  });

  metadata.logCount = logs.length;
  if (logs.length > 0) {
    metadata.startTime = logs[0].timestamp;
    metadata.endTime = logs[logs.length - 1].timestamp;
  }

  return { 
    metadata, logs, lifecycleEvents, billingLogs, billingFlows, 
    storageInfo, diagnosis: { status: 'SUCCESS', summary: '정상', issues: [], csType: 'NONE' }, 
    fileList: [], obdSeries, metrics: aggregateMetrics(obdSeries) 
  };
};

import React, { useState } from 'react';
import { BillingEntry, BillingFlow, StorageStatus } from '../types';
import { 
  CreditCard, AlertCircle, CheckCircle, ShoppingBag, 
  Fingerprint, Info, Database, Code, ShieldAlert,
  ArrowRight, Clock, FileText, ChevronDown, ChevronUp
} from 'lucide-react';

interface BillingListProps {
  entries: BillingEntry[];
  flows: BillingFlow[];
  storage?: StorageStatus;
}

const JsonViewer: React.FC<{ data: string }> = ({ data }) => {
  const [isOpen, setIsOpen] = useState(false);
  let formatted = data;
  try { formatted = JSON.stringify(JSON.parse(data), null, 2); } catch {}

  return (
    <div className="mt-2">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center gap-1.5 px-3 py-1 rounded bg-slate-800 text-slate-300 text-[10px] font-bold hover:bg-slate-700 transition-colors"
      >
        <Code className="w-3 h-3" /> {isOpen ? 'JSON 닫기' : 'JSON 상세 보기'}
      </button>
      {isOpen && (
        <pre className="mt-2 p-3 bg-slate-900 text-emerald-400 text-[10px] font-mono rounded border border-slate-700 overflow-x-auto whitespace-pre-wrap max-h-60 custom-scrollbar">
          {formatted}
        </pre>
      )}
    </div>
  );
};

const StepIcon: React.FC<{ status: 'done' | 'active' | 'pending' | 'fail' }> = ({ status }) => {
  if (status === 'done') return <div className="w-5 h-5 rounded-full bg-emerald-500 flex items-center justify-center text-white"><CheckCircle className="w-3.5 h-3.5" /></div>;
  if (status === 'fail') return <div className="w-5 h-5 rounded-full bg-red-500 flex items-center justify-center text-white"><AlertCircle className="w-3.5 h-3.5" /></div>;
  if (status === 'active') return <div className="w-5 h-5 rounded-full bg-indigo-600 flex items-center justify-center text-white animate-pulse"><Clock className="w-3.5 h-3.5" /></div>;
  return <div className="w-5 h-5 rounded-full bg-slate-200" />;
};

const TransactionFlowCard: React.FC<{ flow: BillingFlow }> = ({ flow }) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const startTimeStr = flow.startTime.toLocaleTimeString();

  return (
    <div className={`bg-white rounded-2xl border transition-all ${isExpanded ? 'shadow-md border-indigo-200' : 'border-slate-200 shadow-sm'}`}>
      <div className="p-5 flex flex-col md:flex-row md:items-center gap-6">
        {/* Status & Time */}
        <div className="shrink-0 flex flex-col items-center justify-center md:border-r border-slate-100 pr-6">
          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-1 ${
            flow.finalStatus === 'SUCCESS' ? 'bg-emerald-100 text-emerald-600' :
            flow.finalStatus === 'FAILURE' ? 'bg-red-100 text-red-600' : 'bg-indigo-100 text-indigo-600'
          }`}>
            <ShoppingBag className="w-6 h-6" />
          </div>
          <span className="text-[10px] font-mono font-bold text-slate-400">{startTimeStr}</span>
        </div>

        {/* Stepper */}
        <div className="flex-1">
          <div className="flex items-center gap-2 mb-3">
             <span className={`text-[10px] font-black px-2 py-0.5 rounded-full ${
               flow.finalStatus === 'SUCCESS' ? 'bg-emerald-50 text-emerald-700' :
               flow.finalStatus === 'FAILURE' ? 'bg-red-50 text-red-700' : 'bg-indigo-50 text-indigo-700'
             }`}>
               {flow.finalStatus} TRANSACTION
             </span>
             <span className="text-xs font-bold text-slate-700">Google Play 결제 핸드쉐이크</span>
          </div>

          <div className="flex items-center gap-0 w-full max-w-md">
            <div className="flex flex-col items-center gap-1 flex-1">
              <StepIcon status={flow.hasPurchase ? 'done' : 'pending'} />
              <span className="text-[9px] font-bold text-slate-400">PURCHASE</span>
            </div>
            <div className={`h-0.5 flex-1 ${flow.hasSignature ? 'bg-emerald-500' : 'bg-slate-100'}`} />
            <div className="flex flex-col items-center gap-1 flex-1">
              <StepIcon status={flow.hasSignature ? 'done' : (flow.finalStatus === 'FAILURE' ? 'fail' : 'pending')} />
              <span className="text-[9px] font-bold text-slate-400">SIGNATURE</span>
            </div>
            <div className={`h-0.5 flex-1 ${flow.hasReceipt ? 'bg-emerald-500' : 'bg-slate-100'}`} />
            <div className="flex flex-col items-center gap-1 flex-1">
              <StepIcon status={flow.hasReceipt ? 'done' : (flow.finalStatus === 'FAILURE' ? 'fail' : 'pending')} />
              <span className="text-[9px] font-bold text-slate-400">VERIFY</span>
            </div>
          </div>
        </div>

        {/* Toggle */}
        <button 
          onClick={() => setIsExpanded(!isExpanded)}
          className="px-4 py-2 rounded-xl bg-slate-50 hover:bg-slate-100 text-slate-500 transition-colors"
        >
          {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
        </button>
      </div>

      {isExpanded && (
        <div className="px-5 pb-5 border-t border-slate-50 pt-5 space-y-4 animate-in slide-in-from-top-2">
          {flow.steps.map((step, idx) => (
            <div key={idx} className="bg-slate-50/50 p-4 rounded-xl border border-slate-100">
              <div className="flex items-center justify-between mb-2">
                <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded">{step.type}</span>
                <span className="text-[10px] font-mono text-slate-400">{step.rawTimestamp.split(' ')[1]}</span>
              </div>
              <p className="text-xs text-slate-700 font-bold mb-2">{step.message}</p>
              {step.jsonData && <JsonViewer data={step.jsonData} />}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

